\begin{aligned}
0.125 \times 2 &= 0.25 \quad \text{integer part } 0 \\
0.25 \times 2 &= 0.5 \quad \text{integer part } 0 \\
0.5 \times 2 &= 1.0 \quad \text{integer part } 1 \\
\end{aligned}

\begin{aligned}
\text{Total Instructions} &= N_{\text{ALU}} + N_{\text{Branch}} + N_{\text{SW}} + N_{\text{LW}} \\
&= 200 \times 10^6 + 55 \times 10^6 + 25 \times 10^6 + 20 \times 10^6 \\
&= 300 \times 10^6 \quad \text{(300 million instructions)}
\end{aligned}

\begin{aligned}
\text{Cycles}_{\text{ALU}} &= 200 \times 10^6 \times 3 = 600 \times 10^6 \\
\text{Cycles}_{\text{Branch}} &= 55 \times 10^6 \times 2 = 110 \times 10^6 \\
\text{Cycles}_{\text{SW}} &= 25 \times 10^6 \times 4 = 100 \times 10^6 \\
\text{Cycles}_{\text{LW}} &= 20 \times 10^6 \times 5 = 100 \times 10^6 \\
\text{Total Cycles} &= (600 + 110 + 100 + 100) \times 10^6 = 910 \times 10^6 \quad \text{(910 million cycles)}
\end{aligned}

\begin{aligned}
\text{CPU Time} &= \text{Total Cycles} \times \text{Clock cycle time} \\
&= (910 \times 10^6) \times (1 \times 10^{-9}) \\
&= 910 \times 10^{-3} \text{ seconds} \\
&= 0.91 \text{ seconds}
\end{aligned}

