digraph G {
    rankdir=LR;
    node [shape=box];

    // Pipeline stages
    IF [label="IF\nInstruction Fetch"];
    ID [label="ID\nInstruction Decode\nRegister Read"];
    EX [label="EX\nExecute/ALU"];
    MEM [label="MEM\nMemory Access"];
    WB [label="WB\nWrite Back"];

    // Pipeline registers
    IF_ID [label="IF/ID", shape=plaintext];
    ID_EX [label="ID/EX", shape=plaintext];
    EX_MEM [label="EX/MEM", shape=plaintext];
    MEM_WB [label="MEM/WB", shape=plaintext];

    // Forwarding paths
    EX_MEM -> EX [label="Forward from EX/MEM", style=dashed, color=blue];
    MEM_WB -> EX [label="Forward from MEM/WB", style=dashed, color=green];

    // Hazard detection unit
    HD [label="Hazard Detection Unit", shape=ellipse];
    HD -> ID_EX [label="Monitor dest regs", style=dotted];
    HD -> EX_MEM [style=dotted];
    HD -> MEM_WB [style=dotted];
    HD -> ID [label="Monitor src regs", style=dotted];

    // Normal pipeline flow
    IF -> IF_ID -> ID -> ID_EX -> EX -> EX_MEM -> MEM -> MEM_WB -> WB;

    // Forwarding multiplexers at EX inputs
    subgraph cluster_ALU_inputs {
        label="ALU Inputs with Forwarding Muxes";
        color=lightgrey;
        MUX1 [label="MUX", shape=circle];
        MUX2 [label="MUX", shape=circle];
        RegisterFile [label="Register File", shape=cylinder];

        RegisterFile -> MUX1 [label="Normal path"];
        RegisterFile -> MUX2 [label="Normal path"];
        EX_MEM -> MUX1 [label="Forward path", style=dashed, color=blue];
        EX_MEM -> MUX2 [label="Forward path", style=dashed, color=blue];
        MEM_WB -> MUX1 [label="Forward path", style=dashed, color=green];
        MEM_WB -> MUX2 [label="Forward path", style=dashed, color=green];
        MUX1 -> EX;
        MUX2 -> EX;
    }
}
